    /**
     * Pre-validates the algorithm in the JWT header before full parsing.
     * This prevents algorithm confusion/substitution attacks.
     */
    private void validateTokenAlgorithm(String token) {
        // Decode only the header (first segment) without verification to check the algorithm
        String[] parts = token.split("\\.");
        if (parts.length < 2) {
            throw new MalformedJwtException("JWT token does not have the expected number of segments");
        }

        String headerJson;
        try {
            headerJson = new String(Base64.getUrlDecoder().decode(parts[0]), StandardCharsets.UTF_8);
        } catch (IllegalArgumentException e) {
            throw new MalformedJwtException("Invalid Base64 in JWT header");
        }

        // Simple extraction of "alg" field - avoid full JSON parsing dependency
        // The jjwt library will do proper parsing, this is a pre-check
        String algorithm = extractAlgFromHeader(headerJson);

        if (algorithm == null || !ALLOWED_ALGORITHMS.contains(algorithm)) {
            throw new UnsupportedJwtException(
                    "JWT algorithm '" + algorithm + "' is not in the allowlist. " +
                    "Allowed algorithms: " + ALLOWED_ALGORITHMS);
        }

        // Explicitly reject "none" algorithm
        if ("none".equalsIgnoreCase(algorithm)) {
            throw new UnsupportedJwtException("JWT 'none' algorithm is not permitted");
        }
    }

    /**
     * Extracts the "alg" value from a JSON header string.
     */
    private String extractAlgFromHeader(String headerJson) {
        // Simple extraction - look for "alg":"value" pattern
        int algIndex = headerJson.indexOf("\"alg\"");
        if (algIndex == -1) {
            return null;
        }

        int colonIndex = headerJson.indexOf(':', algIndex);
        if (colonIndex == -1) {
            return null;
        }

        int firstQuote = headerJson.indexOf('"', colonIndex);
        if (firstQuote == -1) {
            return null;
        }

        int secondQuote = headerJson.indexOf('"', firstQuote + 1);
        if (secondQuote == -1) {
            return null;
        }

        return headerJson.substring(firstQuote + 1, secondQuote);
    }

    /**
     * Extracts authorities/roles from JWT claims.
     */
    @SuppressWarnings("unchecked")
    private List<SimpleGrantedAuthority> extractAuthorities(Claims claims) {
        List<SimpleGrantedAuthority> authorities = new ArrayList<>();

        Object rolesObj = claims.get("roles");
        if (rolesObj instanceof List<?>) {
            List<String> roles = ((List<?>) rolesObj).stream()
                    .filter(String.class::isInstance)
                    .map(String.class::cast)
                    .collect(Collectors.toList());

            for (String role : roles) {
                // Sanitize role name - only allow alphanumeric and underscore
                if (role.matches("^[A-Za-z0-9_]+$")) {
                    String authorityName = role.startsWith("ROLE_") ? role : "ROLE_" + role;
                    authorities.add(new SimpleGrantedAuthority(authorityName));
                } else {
                    logger.warn("Skipping invalid role name in JWT: {}", role);
                }
            }
        }

        Object scopesObj = claims.get("scope");
        if (scopesObj instanceof String) {
            String[] scopes = ((String) scopesObj).split("\\s+");
            for (String scope : scopes) {
                if (scope.matches("^[A-Za-z0-9_:]+$")) {
                    authorities.add(new SimpleGrantedAuthority("SCOPE_" + scope));
                }
            }
        }

        return authorities;
    }

    /**
     * Sends a 401 Unauthorized response with a JSON body.
     */
    private void sendUnauthorizedResponse(HttpServletResponse response, String message) throws IOException {
        response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
        response.setContentType("application/json");
        response.setCharacterEncoding("UTF-8");
        // Don't expose internal details in the response
        response.getWriter().write("{\"error\":\"Unauthorized\",\"message\":\"" +
                message.replace("\"", "\\\"") + "\"}");
        response.getWriter().flush();
    }

